@mixin fluid-multiselect {
  .#{$prefix}--multi-select__wrapper.#{$prefix}--list-box__wrapper--fluid--focus:not(
      .#{$prefix}--multi-select--filterable__wrapper
    )
    .#{$prefix}--list-box__field--wrapper--input-focused {
    outline: none;
  }

  .#{$prefix}--list-box__wrapper--fluid
    .#{$prefix}--tag.#{$prefix}--tag--filter {
    margin-block-start: 1.25rem;
  }

  // Filterable
  .#{$prefix}--list-box__wrapper--fluid
    .#{$prefix}--multi-select--filterable
    .#{$prefix}--list-box__field
    .#{$prefix}--text-input {
    border-block-end: 1px solid transparent;
  }

  .#{$prefix}--list-box__wrapper--fluid
    .#{$prefix}--multi-select--filterable.#{$prefix}--combo-box
    .#{$prefix}--list-box__field {
    align-items: baseline;
  }

  .#{$prefix}--list-box__wrapper--fluid.#{$prefix}--multi-select--filterable__wrapper:not(
      .#{$prefix}--list-box--up
    )
    .#{$prefix}--list-box__menu {
    inset-block-start: calc(100% + convert.to-rem(1px));
  }
}

@else {
  &[data-exiting] .#{$prefix}--modal-container {
    animation: #{$prefix}--presence-modal-container__exit
      $duration-moderate-02
      motion(exit, expressive)
      forwards;

    @media screen and (prefers-reduced-motion: reduce) {
      animation: none;
    }
  }

  .#{$prefix}--modal-container {
    animation: #{$prefix}--presence-modal-container__enter
      $duration-moderate-02
      motion(entrance, expressive)
      forwards;

    @media screen and (prefers-reduced-motion: reduce) {
      animation: none;
    }
  }

  @keyframes #{$prefix}--presence-modal-container__enter {
    from {
      transform: translate3d(0, -24px, 0);
    }

    to {
      transform: translate3d(0, 0, 0);
    }
  }

  @keyframes #{$prefix}--presence-modal-container__exit {
    from {
      transform: translate3d(0, 0, 0);
    }

    to {
      transform: translate3d(0, -24px, 0);
    }
  }
}

@if (config.$use-akamai-cdn) {
  $name: -get-akamai-filename($-akamai-filenames, $name, 'name');
  $filename: -get-akamai-filename($-akamai-filenames, $name, 'filename');

  // Special case for weight = Regular (400)
  @if $weight ==Regular {
    @if $style ==italic {
      $filename: '#{$filename}-Italic';
    } @else {
      $filename: '#{$filename}-Regular';
    }
  } @else {
    // Otherwise add weight + optional style (italic)
    $filename: '#{$filename}-#{$weight}';

    @if $style ==italic {
      $filename: '#{$filename}Italic';
    }
  }

  $filenames: ();

  @each $format in $formats {
    $url: 'https://1.www.s81c.com/common/carbon/plex/fonts/#{$name}';

    @if $unicode-range {
      $url: 'https://1.www.s81c.com/common/carbon/plex/fonts/#{$name}/fonts/split/#{$format}/#{$filename}-#{$unicode-range}';
    } @else {
      $url: 'https://1.www.s81c.com/common/carbon/plex/fonts/#{$name}/fonts/complete/#{$format}/#{$filename}';
    }

    // Add extension
    $url: '#{$url}.#{$format}';
    $filenames: list.append(
      $filenames,
      url('#{$url}') format('#{$format}'),
      $separator: comma
    );
  }

  @return $filenames;
}

@mixin focus-outline($type: 'border') {
  @if ($type == 'border') {
    outline: 1px solid theme.$focus;

    @media screen and (prefers-contrast) {
      outline-style: dotted;
    }
  }

  @if ($type == 'blurred') {
    box-shadow: 0 0 0 3px theme.$focus;
    outline: 1px solid transparent;
  }

  @if ($type == 'outline') {
    outline: 2px solid theme.$focus;
    outline-offset: -2px;

    @media screen and (prefers-contrast) {
      outline-style: dotted;
    }
  }

  @if ($type == 'outline-compat') {
    box-sizing: border-box;
    border: 2px solid theme.$focus;

    @media screen and (prefers-contrast) {
      border-style: dotted;
    }
  }

  @if ($type == 'invalid') {
    outline: 2px solid theme.$support-error;
    outline-offset: -2px;

    @media screen and (prefers-contrast) {
      outline-style: dotted;
    }
  }

  @if ($type == 'reset') {
    outline: 2px solid transparent;
    outline-offset: -2px;
  }
}

@mixin use($group, $default, $min: null, $max: null) {
  $properties: map.get($layout-tokens, $group);

  @each $property, $steps in $properties {
    $minValue: custom-property.get-var('layout-#{$group}-#{$property}-min');
    @if $min {
      $minValue: max(
        $minValue,
        custom-property.get-var('layout-#{$group}-#{$property}-#{$min}')
      );
    }

    $maxValue: custom-property.get-var('layout-#{$group}-#{$property}-max');
    @if $max {
      $maxValue: min(
        $maxValue,
        custom-property.get-var('layout-#{$group}-#{$property}-#{$max}')
      );
    }

    $value: clamp(
      $minValue,
      custom-property.get-var(
        'layout-#{$group}-#{$property}',
        custom-property.get-var('layout-#{$group}-#{$property}-#{$default}')
      ),
      $maxValue
    );

    @include custom-property.declaration(
      'layout-#{$group}-#{$property}-local',
      $value
    );
  }
}

@mixin tooltip--content($tooltip-type: 'icon') {
  @include box-shadow;

  z-index: z('floating');
  @if $tooltip-type == 'definition' {
    padding: $spacing-03 $spacing-05;
  } @else {
    padding: convert.to-rem(3px) $spacing-05;
  }

  border-radius: convert.to-rem(2px);
  background-color: $background-inverse;
  block-size: auto;
  color: $text-inverse;
  font-weight: 400;
  inline-size: max-content;
  max-inline-size: convert.to-rem(208px);
  min-inline-size: convert.to-rem(24px);
  text-align: start;
  transform: translateX(-50%);
  @include type.type-style('body-compact-01');

  // IE media query
  @media all and (-ms-high-contrast: none), (-ms-high-contrast: active) {
    inline-size: auto;
  }
  // Edge 12-15 and Edge 16 feature queries
  @supports (-ms-accelerator: true) {
    inline-size: auto;
  }
  @supports (-ms-ime-align: auto) {
    inline-size: auto;
  }

  // Windows, Firefox HCM Fix
  @media screen and (-ms-high-contrast: active), screen and (prefers-contrast) {
    border: 1px solid transparent;
  }
}

@mixin breadcrumbs-container {
  margin: $breadcrumbs-margin;
  list-style: none;

  @include clearfix;

  // Item wrapper
  li {
    float: #{$global-left};

    font-size: $breadcrumbs-item-font-size;
    color: $breadcrumbs-item-color-current;
    cursor: default;

    @if $breadcrumbs-item-uppercase {
      text-transform: uppercase;
    }

    @if $breadcrumbs-item-separator {
      // Need to escape the backslash
      $separator: if($global-text-direction == 'ltr', $breadcrumbs-item-separator-item, $breadcrumbs-item-separator-item-rtl);

      &:not(:last-child) {
        &::after {
          position: relative;
          margin: 0 $breadcrumbs-item-margin;
          opacity: 1;
          content: $separator;
          color: $breadcrumbs-item-separator-color;
        }
      }
    }
    @else {
      margin-#{$global-right}: $breadcrumbs-item-margin;
    }
  }

  // Page links
  a {
    color: $breadcrumbs-item-color;

    &:hover {
      text-decoration: underline;
    }
  }
}

@mixin button-group-expand(
  $selector: $buttongroup-child-selector,
  $spacing: $buttongroup-spacing,
  $count: null
) {
  @if not $global-flexbox {
    margin-#{$global-right}: -$spacing;

    &::before,
    &::after {
      display: none; // Disable clearfix
    }
  }

  #{$selector} {
    @if $global-flexbox {
      flex: 1 1 0px; // sass-lint:disable-line zero-unit
    }
    @else {
      // One child
      &:first-child {
        &:last-child {
          width: calc(100% - #{$spacing});
        }
      }

      // Two or more childreen
      @for $i from 2 through $buttongroup-expand-max {
        &:first-child:nth-last-child(#{$i}) {
          &, &:first-child:nth-last-child(#{$i}) ~ #{$selector} {
            display: inline-block;
            width: calc(#{percentage(divide(1, $i))} - #{$spacing});
            margin-#{$global-right}: $spacing;

            &:last-child {
              margin-#{$global-right}: $spacing * -$buttongroup-expand-max;
            }
          }
        }
      }
    }
  }
}

@mixin foundation-flex-classes {
  // Horizontal alignment using justify-content
  @each $hdir, $prop in $-zf-flex-justify {
    .align-#{$hdir} {
      @include flex-align($x: $hdir);
    }
  }

  // Horizontal alignment Specifically for Vertical Menu
  @each $hdir, $prop in map-remove($-zf-flex-justify, 'justify', 'spaced') {
    .align-#{$hdir} {
      &.vertical {
        &.menu > li > a {
          @include flex-align($x: $hdir);
        }
      }
    }
  }

  // Vertical alignment using align-items and align-self
  @each $vdir, $prop in $-zf-flex-align {
    .align-#{$vdir} {
      @include flex-align($y: $vdir);
    }

    .align-self-#{$vdir} {
      @include flex-align-self($y: $vdir);
    }
  }

  // Central alignment of content
  .align-center-middle {
    @include flex-align($x: center, $y: middle);
    align-content: center;
  }

  // Source ordering
  @include -zf-each-breakpoint {
    @for $i from 1 through $flex-source-ordering-count {
      .#{$-zf-size}-order-#{$i} {
        @include flex-order($i);
      }
    }
  }

  // Vanilla Flexbox Helpers
  @include flex-helpers;
}

@mixin off-canvas-base(
  $background: $offcanvas-background,
  $transition: $offcanvas-transition-length $offcanvas-transition-timing,
  $fixed: true
) {
  // Set the off-canvas z-index.
  z-index: $offcanvas-push-zindex;
  transition: transform $transition;
  backface-visibility: hidden;
  background: $background;

  @if $fixed == true {
    position: fixed;
  }
  @else {
    position: absolute;
  }

  @include disable-mouse-outline;

  // Increase CSS specificity
  &.is-transition-push {
    z-index: $offcanvas-push-zindex;
  }

  // Hide inactive off-canvas within the content that have the same position
  &.is-closed {
    visibility: hidden;
  }

  // Overlap only styles.
  &.is-transition-overlap {
    z-index: $offcanvas-overlap-zindex;

    &.is-open {
      box-shadow: $offcanvas-shadow;
    }
  }

  // Sets transform to 0 to show an off-canvas panel.
  &.is-open {
    transform: translate(0, 0);
  }
}

@mixin foundation-switch {
  // Container class
  .switch {
    @include switch-container;
    height: $switch-height;
  }

  // <input> element
  .switch-input {
    @include switch-input;
  }

  // <label> element
  .switch-paddle {
    @include switch-paddle;
  }

  // Base label text styles
  %switch-text {
    @include switch-text;
  }

  // Active label text styles
  .switch-active {
    @extend %switch-text;
    @include switch-text-active;
  }

  // Inactive label text styles
  .switch-inactive {
    @extend %switch-text;
    @include switch-text-inactive;
  }

  // Switch sizes
  .switch.tiny {
    @include switch-size(rem-calc(10), $switch-height-tiny, $switch-paddle-offset);
  }

  .switch.small {
    @include switch-size(rem-calc(12), $switch-height-small, $switch-paddle-offset);
  }

  .switch.large {
    @include switch-size(rem-calc(16), $switch-height-large, $switch-paddle-offset);
  }
}

@mixin form-element {
  $height: ($input-font-size * unitless-calc($input-line-height)) + (get-side($input-padding, 'top') + get-side($input-padding, 'bottom')) - rem-calc(1);

  display: block;
  box-sizing: border-box;
  width: 100%;
  height: $height;
  margin: 0 0 $form-spacing;
  padding: $input-padding;

  border: $input-border;
  border-radius: $input-radius;
  background-color: $input-background;
  box-shadow: $input-shadow;

  font-family: $input-font-family;
  font-size: $input-font-size;
  font-weight: $input-font-weight;
  line-height: $input-line-height;
  color: $input-color;

  @if has-value($input-transition) {
    transition: $input-transition;
  }

  // Focus state
  &:focus {
    outline: none;
    border: $input-border-focus;
    background-color: $input-background-focus;
    box-shadow: $input-shadow-focus;

    @if has-value($input-transition) {
      transition: $input-transition;
    }
  }
}

@mixin foundation-prototype-overflow {
  @each $overflow in $prototype-overflow {
    .overflow-#{$overflow} {
      @include overflow($overflow);
    }
    .overflow-x-#{$overflow} {
      @include overflow-x($overflow);
    }
    .overflow-y-#{$overflow} {
      @include overflow-y($overflow);
    }
  }

  @if ($prototype-overflow-breakpoints) {
    // Loop through Responsive Breakpoints
    @each $size in $breakpoint-classes {
      @include breakpoint($size) {
        @each $overflow in $prototype-overflow {
          @if $size != $-zf-zero-breakpoint {
            .#{$size}-overflow-#{$overflow} {
              @include overflow($overflow);
            }
            .#{$size}-overflow-x-#{$overflow} {
              @include overflow-x($overflow);
            }
            .#{$size}-overflow-y-#{$overflow} {
              @include overflow-y($overflow);
            }
          }
        }
      }
    }
  }
}

@mixin foundation-prototype-position {
  // Position: Static, Relative, Fixed, Absolute
  @each $position in $prototype-position {
    .position-#{$position} {
      @include position($position);
    }
  }

  // Position: Fixed Top, Fixed Bottom
  .position-fixed-top {
    @include position-fixed-top;
  }
  .position-fixed-bottom {
    @include position-fixed-bottom;
  }

  @if ($prototype-position-breakpoints) {
    // Loop through Responsive Breakpoints
    @each $size in $breakpoint-classes {
      @include breakpoint($size) {
        // Position: Static, Relative, Fixed, Absolute
        @each $position in $prototype-position {
          @if $size != $-zf-zero-breakpoint {
            .#{$size}-position-#{$position} {
              @include position($position);
            }
          }
        }

        // Position: Fixed Top, Fixed Bottom
        @if $size != $-zf-zero-breakpoint {
          .#{$size}-position-fixed-top {
            @include position-fixed-top;
          }

          .#{$size}-position-fixed-bottom {
            @include position-fixed-bottom;
          }
        }
      }
    }
  }
}

@if ($prototype-spacing-breakpoints) {
  @for $spacer from 0 through $prototype-spacers-count {
    // Loop through Responsive Breakpoints
    @each $size in $breakpoint-classes {
      @include breakpoint($size) {
        @if $size != $-zf-zero-breakpoint {
          .#{$size} {
            @each $prop in (margin, padding) {
              // All Sides
              &-#{$prop}-#{$spacer} {
                @if ($prop == margin) {
                  margin: $spacer * $global-margin !important;
                }
                @else if ($prop == padding) {
                  padding: $spacer * $global-padding !important;
                }
              }

              @each $dir in (top, right, bottom, left, horizontal, vertical) {
                // Top Side
                &-#{$prop}-#{$dir}-#{$spacer} {
                  @if ($prop == margin) {
                    @include margin-direction($dir, $spacer);
                  }
                  @else if ($prop == padding) {
                    @include padding-direction($dir, $spacer);
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

@for $spacer from 0 through $prototype-spacers-count {
  // Loop through Responsive Breakpoints
  @each $size in $breakpoint-classes {
    @include breakpoint($size) {
      @if $size != $-zf-zero-breakpoint {
        .#{$size} {
          @each $prop in (margin, padding) {
            // All Sides
            &-#{$prop}-#{$spacer} {
              @if ($prop == margin) {
                margin: $spacer * $global-margin !important;
              }
              @else if ($prop == padding) {
                padding: $spacer * $global-padding !important;
              }
            }

            @each $dir in (top, right, bottom, left, horizontal, vertical) {
              // Top Side
              &-#{$prop}-#{$dir}-#{$spacer} {
                @if ($prop == margin) {
                  @include margin-direction($dir, $spacer);
                }
                @else if ($prop == padding) {
                  @include padding-direction($dir, $spacer);
                }
              }
            }
          }
        }
      }
    }
  }
}

@function -zf-get-bp-val($map, $value) {
  // If the given map is a single value, return it
  @if type-of($map) == 'number' {
    @return $map;
  }


  // Check if the breakpoint name exists globally
  @if not map-has-key($breakpoints, $value) {
    @if type-of($value) == 'number' {
      $value: -zf-closest-named-breakpoint($value);
    } @else {
      @return null;
    }
  }
  // Check if the breakpoint name exists in the local config map
  @else if map-has-key($map, $value) {
    // If it does, just return the value
    @return map-get($map, $value);
  }
  // Otherwise, find the next lowest breakpoint and return that value
  @else {
    $anchor: null;
    $found: false;

    @each $key, $val in $breakpoints {
      @if not $found {
        @if map-has-key($map, $key) {
          $anchor: $key;
        }
        @if $key == $value {
          $found: true;
        }
      }
    }

    @return map-get($map, $anchor);
  }
}

@function divide($dividend, $divisor, $precision: 12) {
  $sign: if($dividend > 0 and $divisor > 0 or $dividend < 0 and $divisor < 0, 1, -1);
  $dividend: math.abs($dividend);
  $divisor: math.abs($divisor);
  @if $dividend == 0 {
    @return 0;
  }
  @if $divisor == 0 {
    @error 'Cannot divide by 0';
  }
  $remainder: $dividend;
  $result: 0;
  $factor: 10;
  @while ($remainder > 0 and $precision >= 0) {
    $quotient: 0;
    @while ($remainder >= $divisor) {
      $remainder: $remainder - $divisor;
      $quotient: $quotient + 1;
    }
    $result: $result * 10 + $quotient;
    $factor: $factor * 0.1;
    $remainder: $remainder * 10;
    $precision: $precision - 1;
    @if ($precision < 0 and $remainder >= $divisor * 5) {
      $result: $result + 1;
    }
  }
  $result: $result * $factor * $sign;
  $dividend-unit: unit($dividend);
  $divisor-unit: unit($divisor);
  $unit-map: (
    'px': 1px,
    'rem': 1rem,
    'em': 1em,
    '%': 1%
  );
  @if ($dividend-unit != $divisor-unit and map-has-key($unit-map, $dividend-unit)) {
    $result: $result * map-get($unit-map, $dividend-unit);
  }

  @return $result;
}

@mixin xy-block-grid-classes($margin-grid: true, $padding-grid: true) {
  @if $padding-grid {
    @include -zf-each-breakpoint {
      @for $i from 1 through $xy-block-grid-max {
        .#{$-zf-size}-up-#{$i} {
          @include xy-grid-layout($n: $i, $selector: '.cell', $gutter-type: padding, $output: (size));
        }
      }
    }
  }

  @if $margin-grid {
    @include -zf-each-breakpoint {
      @for $i from 1 through $xy-block-grid-max {
        // This is purely for responsive gutters - the margin grid has to go back and adjust widths (or heights)
        // for prior breakpoints based on the responsive gutter.
        @if(type-of($grid-margin-gutters) == 'map' and map-has-key($grid-margin-gutters, $-zf-size)) {
          @each $bp in -zf-breakpoints-less-than($-zf-size) {
            @if(map-has-key($grid-margin-gutters, $bp)) {
              .grid-margin-x.#{$bp}-up-#{$i} {
                @include xy-grid-layout($n: $i, $selector: '.cell', $gutter-type: margin, $output: (size));
              }
            }
          }
        }
      }
      @for $i from 1 through $xy-block-grid-max {
        .grid-margin-x.#{$-zf-size}-up-#{$i} {
          @include xy-grid-layout($n: $i, $selector: '.cell', $gutter-type: margin, $output: (size));
        }
      }
    }
  }
}

@mixin foundation-xy-grid-classes(
  $base-grid: true,
  $margin-grid: true,
  $padding-grid: true,
  $block-grid: true,
  $collapse: true,
  $offset: true,
  $vertical-grid: true,
  $frame-grid: true
) {

  // Base grid styles
  @if($base-grid) {
    @include xy-base-grid-classes();
  }

  // Margin grid
  @if($margin-grid) {
    @include xy-margin-grid-classes();
  }

  // Padding grid
  @if($padding-grid) {
    @include xy-padding-grid-classes();
  }

  // Block grid
  @if($block-grid) {
    @include xy-block-grid-classes($margin-grid, $padding-grid);
  }

  // Collapse gutters
  @if($collapse) {
    @include xy-collapse-grid-classes($margin-grid, $padding-grid);
  }

  // Offset gutters
  @if($offset) {
    @include xy-offset-cell-classes();
  }

  // Vertical grid
  @if($vertical-grid) {
    @include xy-vertical-grid-classes($margin-grid, $padding-grid);
  }

  @if ($frame-grid) {
    @include xy-frame-grid-classes($vertical-grid, $margin-grid)
  }
}

@if ($gutter-type == 'margin') {

  @include breakpoint($min-breakpoint) {
    @each $value in $gutter-position {
      margin-#{$value}: 0;
    }

    > #{$selector} {
      @each $value in $gutter-position {
        margin-#{$value}: 0;
      }
    }
  }

  $excluded-bps: -zf-breakpoints-less-than($min-breakpoint);

  // Output new widths to not include gutters
  @each $bp in $breakpoint-classes {
    @if(sl-contain($excluded-bps, $bp)) {
      @include breakpoint($min-breakpoint) {
        @for $i from 1 through $grid-columns {
          // Sizing (percentage)
          > .#{$bp}-#{$i} {
            @include xy-cell-size($i, $gutter-type: none);
          }
        }
      }
    } @else {
      @include breakpoint($bp) {
        @for $i from 1 through $grid-columns {
          // Sizing (percentage)
          > .#{$bp}-#{$i} {
            @include xy-cell-size($i, $gutter-type: none);
          }
        }
      }
    }
  }
}

table {
  display: block;
  width: 100%; // keep for backwards compatibility
  width: max-content;
  max-width: 100%;
  overflow: auto;
  font-variant: tabular-nums;

  th {
    // stylelint-disable-next-line primer/typography
    font-weight: $font-weight-bold;
  }

  th,
  td {
    // stylelint-disable-next-line primer/spacing
    padding: 6px 13px;
    // stylelint-disable-next-line primer/borders, primer/colors
    border: $border-width $border-style var(--borderColor-default, var(--color-border-default));
  }

  td {
    > :last-child {
      margin-bottom: 0;
    }
  }

  tr {
    background-color: var(--bgColor-default, var(--color-canvas-default));
    // stylelint-disable-next-line primer/borders, primer/colors
    border-top: $border-width $border-style var(--borderColor-muted, var(--color-border-muted));

    &:nth-child(2n) {
      background-color: var(--bgColor-muted, var(--color-canvas-subtle));
    }
  }

  img {
    background-color: transparent;
  }
}

a,
  span,
  em {
    min-width: 32px;
    // stylelint-disable-next-line primer/spacing
    padding: 5px 10px;
    font-style: normal;
    // stylelint-disable-next-line primer/typography
    line-height: 20px;
    color: var(--fgColor-default, var(--color-fg-default));
    text-align: center;
    white-space: nowrap;
    vertical-align: middle;
    cursor: pointer;
    user-select: none;
    // stylelint-disable-next-line primer/borders, primer/colors
    border: $border-width $border-style transparent;
    // stylelint-disable-next-line primer/borders
    border-radius: $border-radius;
    transition: border-color 0.2s cubic-bezier(0.3, 0, 0.5, 1);

    &:hover,
    &:focus {
      text-decoration: none;
      border-color: var(--borderColor-default, var(--color-border-default));
      transition-duration: 0.1s;
    }

    &:active {
      border-color: var(--borderColor-muted, var(--color-border-muted));
      transition: none;
    }
  }

@mixin double-caret($background: var(--bgColor-default, var(--color-canvas-default)), $border: var(--borderColor-default, var(--color-border-default))) {
  // stylelint-disable nesting-selector-no-missing-scoping-root
  &::after,
  &::before {
    position: absolute;
    // stylelint-disable-next-line primer/spacing
    top: 11px;
    right: 100%;
    left: calc(var(--base-size-8) * -1);
    display: block;
    width: 8px;
    height: 16px;
    pointer-events: none;
    content: ' ';
    clip-path: polygon(0 50%, 100% 0, 100% 100%);
  }

  &::after {
    // stylelint-disable-next-line primer/spacing
    margin-left: 2px;
    background-color: var(--bgColor-default, var(--color-canvas-default));
    background-image: linear-gradient($background, $background);
  }

  &::before {
    // stylelint-disable-next-line primer/colors
    background-color: $border;
  }
  // stylelint-enable nesting-selector-no-missing-scoping-root
}

> .card {
  flex: 1 0 0;
  margin-bottom: 0;

  + .card {
    margin-left: 0;
    border-left: 0;
  }

  // Handle rounded corners
  @if $enable-rounded {
    &:not(:last-child) {
      @include border-end-radius(0);

      > .card-img-top,
      > .card-header {
        // stylelint-disable-next-line property-disallowed-list
        border-top-right-radius: 0;
      }
      > .card-img-bottom,
      > .card-footer {
        // stylelint-disable-next-line property-disallowed-list
        border-bottom-right-radius: 0;
      }
    }

    &:not(:first-child) {
      @include border-start-radius(0);

      > .card-img-top,
      > .card-header {
        // stylelint-disable-next-line property-disallowed-list
        border-top-left-radius: 0;
      }
      > .card-img-bottom,
      > .card-footer {
        // stylelint-disable-next-line property-disallowed-list
        border-bottom-left-radius: 0;
      }
    }
  }
}

@if $enable-container-classes {
  // Single container class with breakpoint max-widths
  .container,
  // 100% wide container at all breakpoints
  .container-fluid {
    @include make-container();
  }

  // Responsive containers that are 100% wide until a breakpoint
  @each $breakpoint, $container-max-width in $container-max-widths {
    .container-#{$breakpoint} {
      @extend .container-fluid;
    }

    @include media-breakpoint-up($breakpoint, $grid-breakpoints) {
      %responsive-container-#{$breakpoint} {
        max-width: $container-max-width;
      }

      // Extend each breakpoint which is smaller or equal to the current breakpoint
      $extend-breakpoint: true;

      @each $name, $width in $grid-breakpoints {
        @if ($extend-breakpoint) {
          .container#{breakpoint-infix($name, $grid-breakpoints)} {
            @extend %responsive-container-#{$breakpoint};
          }

          // Once the current breakpoint is reached, stop extending
          @if ($breakpoint == $name) {
            $extend-breakpoint: false;
          }
        }
      }
    }
  }
}
